-- ============================================================
-- 019b – SEED: Doku-Vorlagen (Platzhalter-Katalog aus Cockpit v4)
-- Wiederholbar: ON CONFLICT aktualisiert Struktur + Positionen.
-- Inhalte sind PLATZHALTER (quelle: platzhalter_v4), echte
-- Praxistexte ersetzen sie später über dasselbe Upsert-Muster.
-- ============================================================

ON CONFLICT (behandlungsart, termin_typ) DO UPDATE SET
  name = EXCLUDED.name,
  sort_index = EXCLUDED.sort_index,
  aktiv = EXCLUDED.aktiv,
  struktur = EXCLUDED.struktur,
  positionen = EXCLUDED.positionen,
  updated_at = NOW();

-- Kontrolle:
SELECT behandlungsart, termin_typ, name,
       jsonb_array_length(positionen) AS positionen_anzahl
FROM doku_vorlagen ORDER BY behandlungsart, sort_index;
